  ('aboriginal-8b44517b-moex-00074', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '有關公務員懲處之敘述，下列何者正確？ 由公務員所屬機關之長官發動並處分 政務官假日酒駕之行為應受懲處 不服懲處處分之公務員得向公務人員保障暨培訓委員會提起申訴 懲處處分應由考試院審定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00075', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '公務人員年終考績78分，屬於下列何等第？ 甲等  乙等  丙等  丁等', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00076', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '有關公物及公營造物使用之敘述，下列何者錯誤？ 公物使用關係之性質，縱有收取費用，亦非必然屬私經濟關係 公有市場與利用人間之法律關係，依據實務見解乃為私法關係 人民經許可於公有道路作特殊使用，其利用關係屬公法關係 公有道路通車開放使用為一般處分', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00077', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '依再生能源發展條例第9條規定：「中央主管機關應邀集相關各部會、學者專家、團體組成委員會， 審定再生能源發電設備生產電能之躉購費率及其計算公式，必要時得依行政程序法舉辦聽證會後公告 之。」關於此規定，下列敘述何者正確？ 該聽證得依當事人之申請，由主持人決定全部不公開 該聽證具有終結程序之效力，行政機關不得再為聽證 該躉購費率與計算公式之公告，屬於裁量性行政規則 該費率審定委員會之性質，屬於獨立的行政管制機關', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00078', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '行政機關基於法律授權，對多數不特定人民就一般事項所作抽象之對外發生法律效果之規定。稱為： 法規命令  職權命令  行政規則  緊急命令', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00079', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '下列行政處分何者得撤銷？ 未表明處分機關之行政處分  許可違法之賭博 對已死亡之人作成之行政處分  未明確敘明違法事證所為之裁罰處分', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00080', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '國營金融機構以函文檢送主管機關之公函通知各退休人員關於新優惠存款改革方案內容，涉及相對人 權益變更。其法律性質為何？ 行政處分  事實行為  行政契約  私法行為', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00081', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '關於違法行政處分撤銷之敘述，下列何者錯誤？ 2年撤銷期限為除斥期間 撤銷原因包括認定事實及適用法規之瑕疵 自有權撤銷機關確實知曉原處分違法，起算除斥期間 僅上級機關得撤銷違法行政處分', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL)
